#include <bits/stdc++.h>
using namespace std;

const int N=305;

struct Edge{
    int to,val;
};

bool operator<(Edge x,Edge y){
    return x.val<y.val;
}

int n,s,p,q,fa[N],dist[N],f[N],ans=2e9;
bool b[N],del[N];
vector<Edge> g[N];

void dfs(int x){
    for(Edge y:g[x])
        if(y.to!=fa[x]){
            dist[y.to]=dist[x]+y.val;
            fa[y.to]=x;
            dfs(y.to);
        }
}

void dfs2(int x){
    for(Edge y:g[x])
        if(y.to!=fa[x]){
            dfs2(y.to);
            if(!b[y.to])
                f[x]=max(f[x],f[y.to]+y.val);
        }
}

int main(){
    scanf("%d%d",&n,&s);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        g[v].push_back({u,w});
    }
    dfs(1);
    for(int i=1;i<=n;i++)
        if(dist[i]>dist[p])
            p=i;
    memset(dist,0,sizeof(dist));
    memset(fa,0,sizeof(fa));
    dfs(p);
    for(int i=1;i<=n;i++)
        if(dist[i]>dist[q])
            q=i;
    for(int i=q;i;i=fa[i])
        b[i]=1;
    dfs2(p);
    priority_queue<Edge> qu;
    qu.push({q,f[q]});
    for(int i=q,j=q;i;i=fa[i]){
        while(fa[j] && dist[i]-dist[fa[j]]<=s)
            j=fa[j],qu.push({j,f[j]});
        while(del[qu.top().to])
            qu.pop();
        ans=min(ans,max(qu.top().val,max(dist[j],dist[q]-dist[i])));
        del[i]=1;
    }
    printf("%d",ans);
    return 0;
}
